"""Check accepted template rows against uberon-edit.obo for likely conceptual duplicates."""
import csv
from pathlib import Path
import re

TEMPLATE = Path("/__w/eval-ont-agent-uberon/eval-ont-agent-uberon/src/templates/hra_bone_parts.template.tsv")
EDIT = Path("/__w/eval-ont-agent-uberon/eval-ont-agent-uberon/src/ontology/uberon-edit.obo")

name_to_id = {}
synonym_to_id = {}
current_id = None
with EDIT.open() as f:
    for line in f:
        line = line.rstrip("\n")
        if line.startswith("[Term]"):
            current_id = None
        elif line.startswith("id: "):
            current_id = line[4:].strip()
        elif line.startswith("name: ") and current_id:
            name_to_id[line[6:].strip().lower()] = current_id
        elif line.startswith("synonym: ") and current_id:
            m = re.match(r'synonym: "([^"]+)"', line)
            if m:
                synonym_to_id.setdefault(m.group(1).lower(), current_id)

rows = list(csv.reader(TEMPLATE.open(), delimiter="\t"))
data_rows = rows[2:]

# For each template row, also check the term name with "of <bone>" suffix removed
partial_dups = []
for row in data_rows:
    rid, label, *_ = row
    label_l = label.lower()
    # Strip the trailing "of <something>"
    base = re.sub(r"\s+of\s+.+$", "", label_l).strip()
    if base and base != label_l:
        if base in name_to_id:
            partial_dups.append((rid, label, base, name_to_id[base], "exact match on stripped name"))
        elif base in synonym_to_id:
            partial_dups.append((rid, label, base, synonym_to_id[base], "synonym match on stripped name"))

print(f"Likely conceptual duplicates (stripping 'of X' suffix): {len(partial_dups)}")
for rid, label, base, target, reason in partial_dups[:30]:
    print(f"  {rid}  {label!r} -> {target} ({base!r}) [{reason}]")
if len(partial_dups) > 30:
    print(f"  ... and {len(partial_dups)-30} more")
EOF
python3 /tmp/check_partial_dups.py
